const newRows = rows.filter(item =>
  (item.json.STATUS || '').toString().trim().toLowerCase() === 'new'
);

if (newRows.length === 0) {
  throw new Error(
    'No ideas with STATUS = "New" found. Open the Ruins_Untold_Ideas sheet '
    + 'and set at least one row to New before running.'
  );
}

// Take the first 10 New rows
const displayRows = newRows.slice(0, 10);

// Build numbered display list (TOPIC only)
const topicList = displayRows
  .map((item, i) => `${i + 1}. ${item.json.TOPIC || '(no topic)'}`)
  .join('\n');

// Stash the filtered rows for the lookup node
const allRows = displayRows.map(r => r.json);

return [{
  json: {
    topicList,
    allRows: JSON.stringify(allRows),
    count: displayRows.length
  }
}];

const selection = parseInt($json["CASE NUMBER"], 10);
const voiceId   = 'Lp2NZJAfG4zDynNcYPSz';

const allRows = JSON.parse($('Aggregate Topics').item.json.allRows);

if (!selection || selection < 1 || selection > allRows.length) {
  throw new Error(
    `Invalid selection "${selection}". Enter 1–${allRows.length}.`
