  ].join('\n');
}).join('\n\n');

const marker  = 'RUINS_MUSIC_EOF';
const writeCmd = [
  `mkdir -p "${audioDir}"`,
  `cat > "${audioDir}/music_prompts.txt" << '${marker}'`,
  `RUINS UNTOLD — MUSIC CUES (${items.length} total)`,
  ``,
  `Generate each cue with your preferred tool and save as:`,
