const response = $input.item.json;
const rawText = response.content[0].text;

let imagePrompts = [], videoPrompts = [], musicPrompts = [], sfxPrompts = [];

try {
  const imgMatch = rawText.match(/IMAGE_PROMPTS[^\[]*([\s\S]*?)(?=VIDEO_PROMPTS|$)/i);
  const vidMatch = rawText.match(/VIDEO_PROMPTS[^\[]*([\s\S]*?)(?=MUSIC_PROMPTS|$)/i);
  const musMatch = rawText.match(/MUSIC_PROMPTS[^\[]*([\s\S]*?)(?=SFX_PROMPTS|$)/i);
  const sfxMatch = rawText.match(/SFX_PROMPTS[^\[]*([\s\S]*?)(?=\n\n[A-Z]|$)/i);

  const extractArray = (match) => {
    if (!match) return [];
    const arrMatch = match[0].match(/\[[\s\S]*\]/);
    if (!arrMatch) return [];
    try { return JSON.parse(arrMatch[0]); } catch(e) { return []; }
  };

  imagePrompts = extractArray(imgMatch);
  videoPrompts = extractArray(vidMatch);
  musicPrompts = extractArray(musMatch);
  sfxPrompts = extractArray(sfxMatch);
} catch(e) {
  console.error('Prompt parse error:', e.message);
}

const prevData = $('Parse Script Response').item.json;

return [{ json: {
  ...prevData,
  imagePrompts,
  videoPrompts,
  musicPrompts,
  sfxPrompts,
  rawPromptsOutput: rawText,
  imageTotalCount: imagePrompts.length,
  videoTotalCount: videoPrompts.length,
  musicTotalCount: musicPrompts.length,
  sfxTotalCount: sfxPrompts.length
}}];

